import { getCookieJar } from '../axios';

const tough = require('tough-cookie');
const Cookie = tough.Cookie;

export function getCookiesFromHeaders(response: any) {
  return (response.headers['set-cookie'] || []).map(Cookie.parse);
}

export function filterCookies(cookies: Array<any>, partialKey: string) {
  return (cookies || []).filter((cookie) => cookie.key.includes(partialKey));
}

export function getCookieFromStore(url: string, key: string) {
  const cookieJar = getCookieJar();
  const found = cookieJar
    .getCookiesSync(url)
    .filter((cookie: any) => cookie.toString().includes(key))
    .pop();
  return found && found.toJSON();
}
